SELECT SUM(total_points) 
FROM contest_participants
WHERE contest_id = 0;

SELECT name, start_time, end_time, buy_in, max_entries, total_points 
FROM contests 
WHERE buy_in = (SELECT MAX(buy_in) FROM contests);

SELECT MAX(prize_pool) AS highest_prize_pool
FROM contests
WHERE sport = 'NBA' AND category = 'Daily';

SELECT COUNT(*)
FROM entries
WHERE contest_id IN (SELECT contest_id FROM contests WHERE sport = 'NBA');
